// Monta um item por conta social ativa
const clip = $('fetch-clip-do-nicho').item.json;
const accounts = $json.publishAccounts || [];
const activeAccounts = accounts.filter(a => a.status === 'active' || a.status === 1);

if (activeAccounts.length === 0) {
  return [{ json: { has_account: false } }];
}

return activeAccounts.map(account => ({
  json: {
    clip_id:          clip.clip_id,
    vizard_video_id:  clip.vizard_video_id,
    titulo_final:     clip.titulo_final || '',
    descricao_final:  clip.descricao_final || '',
    descricao_base:   clip.descricao_base || '',
    hashtags:         clip.hashtags || '',
    nicho:            clip.nicho || '',
    canal_id:         clip.canal_id || '',
    score_clip:       clip.score_clip || 0,
    arquivo_clip_url: clip.arquivo_clip_url || '',

    // Dados da conta social
    account_id:       account.id,
    account_platform: String(account.platform || account.type || 'unknown').toLowerCase(),
    account_name:     account.username || account.page || '',
    has_account:      true
  }
}));

// Avalia resultado da publicacao
const payload = $('loop-by-account').item.json;
const result = $input.first().json;
const isSuccess = Number(result.code) === 2000;

return [{
  json: {
    ...payload,
    publish_success:  isSuccess,
    publish_code:     result.code ?? null,
    publish_error:    isSuccess ? null : JSON.stringify(result).substring(0, 500),
    pub_status:       isSuccess ? 'publicado' : 'erro',
    pub_platform_id:  isSuccess ? (result.data?.id || result.data?.videoId || null) : null
  }
}];

// HTTP error path — marca como erro
const payload = $('loop-by-account').item.json;
const result = $input.first().json;

return [{
  json: {
    ...payload,
    publish_success: false,
    publish_code:    null,
    publish_error:   JSON.stringify(result).substring(0, 500),
    pub_status:      'erro',
    pub_platform_id: null
  }
}];

